import pytest
from source import longest_common_subsequence


def test_longest_common_subsequence_no_double_consumption():
    result = longest_common_subsequence('AAB', 'AB')

    def is_subsequence(subseq, seq):
        it = iter(seq)
        return all(c in it for c in subseq)

    assert is_subsequence(result, 'AAB'), f"'{result}' is not a subsequence of 'AAB'"
    assert is_subsequence(result, 'AB'), f"'{result}' is not a subsequence of 'AB'"
